import React, { useState, useEffect, useRef } from 'react';
import { RefreshCw } from 'lucide-react';

interface CaptchaProps {
  onValidate: (isValid: boolean) => void;
}

export const Captcha: React.FC<CaptchaProps> = ({ onValidate }) => {
  const [captchaText, setCaptchaText] = useState('');
  const [userInput, setUserInput] = useState('');
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const generateCaptcha = () => {
    const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
    let text = '';
    for (let i = 0; i < 6; i++) {
      text += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaText(text);
    setUserInput('');
    onValidate(false);
    return text;
  };

  const drawCaptcha = (text: string) => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#f3f4f6';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    for (let i = 0; i < 5; i++) {
      ctx.strokeStyle = `rgba(${Math.random() * 255}, ${Math.random() * 255}, ${Math.random() * 255}, 0.3)`;
      ctx.beginPath();
      ctx.moveTo(Math.random() * canvas.width, Math.random() * canvas.height);
      ctx.lineTo(Math.random() * canvas.width, Math.random() * canvas.height);
      ctx.stroke();
    }

    ctx.font = 'bold 32px Arial';
    ctx.textBaseline = 'middle';

    for (let i = 0; i < text.length; i++) {
      const x = 20 + i * 35;
      const y = 35 + (Math.random() - 0.5) * 10;
      const angle = (Math.random() - 0.5) * 0.4;

      ctx.save();
      ctx.translate(x, y);
      ctx.rotate(angle);

      ctx.fillStyle = `rgb(${Math.random() * 100}, ${Math.random() * 100}, ${Math.random() * 100})`;
      ctx.fillText(text[i], 0, 0);

      ctx.restore();
    }

    for (let i = 0; i < 30; i++) {
      ctx.fillStyle = `rgba(${Math.random() * 255}, ${Math.random() * 255}, ${Math.random() * 255}, 0.5)`;
      ctx.fillRect(
        Math.random() * canvas.width,
        Math.random() * canvas.height,
        2,
        2
      );
    }
  };

  useEffect(() => {
    const text = generateCaptcha();
    drawCaptcha(text);
  }, []);

  useEffect(() => {
    if (captchaText) {
      drawCaptcha(captchaText);
    }
  }, [captchaText]);

  const handleRefresh = () => {
    const text = generateCaptcha();
    drawCaptcha(text);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const value = e.target.value.toUpperCase();
    setUserInput(value);
    onValidate(value === captchaText);
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center gap-3">
        <canvas
          ref={canvasRef}
          width={230}
          height={70}
          className="border-2 border-gray-300 rounded-lg"
        />
        <button
          type="button"
          onClick={handleRefresh}
          className="p-2 bg-gray-100 hover:bg-gray-200 rounded-lg transition"
          title="Generar nuevo código"
        >
          <RefreshCw className="w-5 h-5 text-gray-600" />
        </button>
      </div>
      <input
        type="text"
        value={userInput}
        onChange={handleInputChange}
        placeholder="Ingresa el código"
        className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent uppercase"
        maxLength={6}
      />
    </div>
  );
};

import React, { createContext, useContext, useEffect, useState } from 'react';
import { User } from '@supabase/supabase-js';
import { supabase, Usuarios, Roles } from '../lib/supabase';

interface AuthContextType {
  user: User | null;
  profile: Usuarios | null;
  userRole: string | null;
  loading: boolean;
  signIn: (email: string, password: string) => Promise<void>;
  signUp: (email: string, password: string, fullName: string, role: string, phone?: string) => Promise<void>;
  signOut: () => Promise<void>;
  resetPassword: (email: string) => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<Usuarios | null>(null);
  const [userRole, setUserRole] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const fetchProfile = async (userId: string) => {
    const { data, error } = await supabase
      .from('usuarios')
      .select('*, roles(nombre_rol)')
      .eq('id', userId)
      .maybeSingle();

    if (error) {
      console.error('Error fetching profile:', error);
      return null;
    }
    return data;
  };

  useEffect(() => {
    const initAuth = async () => {
      try {
        const { data: { session } } = await supabase.auth.getSession();
        setUser(session?.user ?? null);
        if (session?.user) {
          const profileData = await fetchProfile(session.user.id);
          setProfile(profileData);
          setUserRole(profileData?.roles?.nombre_rol?.toLowerCase() || null);
        }
      } catch (error) {
        console.error('Error initializing auth:', error);
      } finally {
        setLoading(false);
      }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
      (async () => {
        try {
          setUser(session?.user ?? null);
          if (session?.user) {
            if (event === 'SIGNED_IN') {
              await new Promise(resolve => setTimeout(resolve, 500));
            }
            const profileData = await fetchProfile(session.user.id);
            setProfile(profileData);
            setUserRole(profileData?.roles?.nombre_rol?.toLowerCase() || null);
          } else {
            setProfile(null);
            setUserRole(null);
          }
        } catch (error) {
          console.error('Error in auth state change:', error);
        }
      })();
    });

    return () => subscription.unsubscribe();
  }, []);

  const signIn = async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    if (error) throw error;
  };

  const signUp = async (email: string, password: string, fullName: string, role: string, phone?: string) => {
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: undefined,
        data: {
          full_name: fullName,
          role: role,
        }
      }
    });

    if (error) throw error;

    // We shouldn't update the `profiles` table anymore. The `usuarios` table 
    // needs to map roles. Wait, in Supabase Auth, how do we insert the user into `usuarios` 
    // now since the Database trigger was possibly dropped?
    // We should ideally call a custom sign_up RPC or rely on a trigger.
    // If phone isn't supported in `usuarios`, we just ignore it.

    // Attempting to manually create the row doesn't hurt if RLS allows it, but 
    // for this task, the database migration handles user creation if they added a Trigger.
    // However, I didn't add a trigger to my 11-tables migration.
    // I need to insert it manually or let a trigger handle it.
    // I will insert it manually for safety if it doesn't exist, and update it.

    if (data.user) {
      // Find role ID
      const authRoleMap: Record<string, string> = {
        'admin': 'Administrador',
        'secretary': 'Secretaría',
        'representative': 'Representante'
      };

      const { data: roleData } = await supabase
        .from('roles')
        .select('id_rol')
        .eq('nombre_rol', authRoleMap[role] || 'Representante')
        .maybeSingle();

      const { error: insertError } = await supabase
        .from('usuarios')
        .upsert({
          id: data.user.id,
          id_rol: roleData?.id_rol,
          nombre_completo: fullName,
          correo: email,
        });

      if (insertError) {
        console.error('Error inserting user:', insertError);
      }
    }
  };

  const signOut = async () => {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
    setProfile(null);
  };

  const resetPassword = async (email: string) => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/reset-password`,
    });
    if (error) throw error;
  };

  return (
    <AuthContext.Provider
      value={{
        user,
        profile,
        userRole,
        loading,
        signIn,
        signUp,
        signOut,
        resetPassword,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

import { createClient } from '@supabase/supabase-js';

// Cloud configuration
const CLOUD_URL = import.meta.env.VITE_SUPABASE_URL;
const CLOUD_ANON_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY;

// Local Docker Supabase configuration (Defaults for `supabase start`)
const LOCAL_URL = 'http://127.0.0.1:54321';
// This is the default anon key for local supabase development, it's public knowledge and safe to commit for local dev only.
const LOCAL_ANON_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImRlZmF1bHQiLCJyb2xlIjoiYW5vbiIsImlhdCI6MTY3OTM4MTU3MiwiZXhwIjoxOTk0OTU3NTcyfQ.5-iJt4H9V-B4l-11y4-40rX4d53X9R7E3bXZgK57LZE';

if (!CLOUD_URL || !CLOUD_ANON_KEY) {
  throw new Error('Missing Supabase environment variables');
}

// We use a custom fetch implementation to enable hybrid connectivity.
// If an operation fails because of a network error, it will automatically
// retry on the local docker database.
let useLocal = false;

const customFetch = async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
  let urlStr = input.toString();

  // If we've already decided to fallback to local, rewrite the URL directly
  if (useLocal) {
    urlStr = urlStr.replace(CLOUD_URL, LOCAL_URL);
  }

  try {
    const response = await fetch(urlStr, init);
    // Add logic if needed for specific 5xx errors, but fetch only throws on Network errs
    return response;
  } catch (error: any) {
    // If it's a network error ("Failed to fetch") and we haven't failed over yet
    if (!useLocal && error.name === 'TypeError' && (error.message === 'Failed to fetch' || error.message.includes('fetch'))) {
      console.warn('Network error detected. Switching to local Supabase Docker database on localhost:54321...');
      useLocal = true;
      // Retry with local URL
      const fallbackUrl = urlStr.replace(CLOUD_URL, LOCAL_URL);
      return fetch(fallbackUrl, init);
    }
    throw error;
  }
};

// Create a single client using the Cloud URL. The custom fetch will dynamically rewrite it
// if the cloud is unreachable. Ensure the anon key passed in headers by supabase-js is handled.
// Actually, supabase JS attaches the Anon Key in headers. The Local Anon Key is different from the Cloud Anon Key.
// Therefore, the customFetch must ALSO rewrite the api keys in the Authorization and apikey headers!

const hybridFetch = async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
  let urlStr = input.toString();
  let currentInit = { ...init };

  if (useLocal) {
    urlStr = urlStr.replace(CLOUD_URL, LOCAL_URL);
    if (currentInit.headers) {
      const headers = new Headers(currentInit.headers);
      if (headers.get('apikey') === CLOUD_ANON_KEY) headers.set('apikey', LOCAL_ANON_KEY);
      if (headers.get('Authorization') === `Bearer ${CLOUD_ANON_KEY}`) headers.set('Authorization', `Bearer ${LOCAL_ANON_KEY}`);

      // Some API endpoints need the JWT from local users. If it's not the anon key but a user token, we should leave it.
      // Remember that auth state (sessions) are tied to instances. If it switches mid-session, auth might fail.

      currentInit.headers = headers;
    }
  }

  try {
    return await fetch(urlStr, currentInit);
  } catch (error: any) {
    if (!useLocal && error.name === 'TypeError' && (error.message.includes('fetch') || error.message.includes('Network'))) {
      console.warn('Network error detected. Switching to Local Supabase...');
      useLocal = true;

      // Retry
      urlStr = urlStr.replace(CLOUD_URL, LOCAL_URL);
      const headers = new Headers(currentInit.headers || {});
      if (headers.get('apikey') === CLOUD_ANON_KEY) headers.set('apikey', LOCAL_ANON_KEY);
      if (headers.get('Authorization') === `Bearer ${CLOUD_ANON_KEY}`) headers.set('Authorization', `Bearer ${LOCAL_ANON_KEY}`);
      currentInit.headers = headers;

      return fetch(urlStr, currentInit);
    }
    throw error;
  }
};

export const supabase = createClient(CLOUD_URL, CLOUD_ANON_KEY, {
  global: {
    fetch: hybridFetch
  }
});

// -------------- TYPE DEFINITIONS (11 TABLAS EN ESPAÑOL) -------------- //

export interface Roles {
  id_rol: string;
  nombre_rol: string;
}

export interface Usuarios {
  id: string; // auth.users.id
  id_rol: string; // foreign key
  nombre_completo: string;
  correo: string;
  created_at: string;
  updated_at: string;
  roles?: Roles; // Joined data
}

export interface Noticias {
  id: string;
  titulo: string;
  contenido: string;
  fecha: string;
  created_at: string;
}

export interface FotoNoticia {
  id: string;
  id_noticia: string;
  ruta_foto: string;
  created_at: string;
}

export interface Horarios {
  id: string;
  seccion: string;
  ruta_pdf: string;
  created_at: string;
}

export interface PlanesEvaluacion {
  id: string;
  materia: string;
  ruta_pdf: string;
  anio_escolar: string;
  created_at: string;
  materias?: Materias; // joined
}

export interface Ausencias {
  id: string;
  id_representante: string;
  nombre_alumno_descripcion: string;
  motivo: string;
  ruta_pdf_justificativo?: string;
  estado: 'pendiente' | 'aprobada' | 'rechazada';
  created_at: string;
}

export interface DocumentosInstitucionales {
  id: string;
  titulo: string;
  ruta_pdf: string;
  created_at: string;
}

export interface LogSistema {
  id: string;
  accion: string;
  usuario_id: string;
  fecha: string;
}

export interface Materias {
  id: string;
  nombre_materia: string;
  created_at: string;
}

export interface ConfiguracionSistema {
  id: string;
  nombre_institucion: string;
  ruta_logo_foto?: string;
  anio_escolar_actual: string;
  created_at: string;
}

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Download, Upload, AlertTriangle, CheckCircle } from 'lucide-react';

export const Backup: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [showRestoreModal, setShowRestoreModal] = useState(false);
  const [backupData, setBackupData] = useState<string>('');
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  const handleExport = async () => {
    setLoading(true);
    setMessage(null);

    try {
      const [
        rolesRes, usuariosRes, noticiasRes, fotoNoticiasRes, horariosRes,
        materiasRes, planesRes, ausenciasRes, documentosRes, configRes, logsRes
      ] = await Promise.all([
        supabase.from('roles').select('*'),
        supabase.from('usuarios').select('*'),
        supabase.from('noticias').select('*'),
        supabase.from('foto_noticia').select('*'),
        supabase.from('horarios').select('*'),
        supabase.from('materias').select('*'),
        supabase.from('planes_evaluacion').select('*'),
        supabase.from('ausencias').select('*'),
        supabase.from('documentos_institucionales').select('*'),
        supabase.from('configuracion_sistema').select('*'),
        supabase.from('log_sistema').select('*'),
      ]);

      const backup = {
        version: '2.0',
        timestamp: new Date().toISOString(),
        data: {
          roles: rolesRes.data || [],
          usuarios: usuariosRes.data || [],
          noticias: noticiasRes.data || [],
          foto_noticia: fotoNoticiasRes.data || [],
          horarios: horariosRes.data || [],
          materias: materiasRes.data || [],
          planes_evaluacion: planesRes.data || [],
          ausencias: ausenciasRes.data || [],
          documentos_institucionales: documentosRes.data || [],
          configuracion_sistema: configRes.data || [],
          log_sistema: logsRes.data || [],
        },
      };

      const dataStr = JSON.stringify(backup, null, 2);
      const dataBlob = new Blob([dataStr], { type: 'application/json' });
      const url = URL.createObjectURL(dataBlob);
      const link = document.createElement('a');
      link.href = url;
      link.download = `backup-${new Date().toISOString().split('T')[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

      setMessage({ type: 'success', text: 'Backup exportado exitosamente' });
    } catch (error) {
      console.error('Error exporting backup:', error);
      setMessage({ type: 'error', text: 'Error al exportar el backup' });
    } finally {
      setLoading(false);
    }
  };

  const handleImport = async () => {
    setLoading(true);
    setMessage(null);

    try {
      const backup = JSON.parse(backupData);

      if (!backup.version || !backup.data) {
        throw new Error('Formato de backup inválido');
      }

      // Orden de inserción para respetar llaves foráneas:
      // 1. roles, materias, usuarios, configuracion_sistema
      // 2. noticias, horarios, documentos_institucionales
      // 3. foto_noticia, planes_evaluacion, ausencias, log_sistema

      // Para simplificar, asumiremos que se restaurarán los que no existan aún
      const { data: existingRoles } = await supabase.from('roles').select('id_rol');
      const existingRolesIds = new Set(existingRoles?.map((r) => r.id_rol) || []);
      const newRoles = backup.data.roles?.filter((r: any) => !existingRolesIds.has(r.id_rol)) || [];
      if (newRoles.length > 0) await supabase.from('roles').insert(newRoles);

      const { data: existingUsuarios } = await supabase.from('usuarios').select('id');
      const existingUsuariosIds = new Set(existingUsuarios?.map((u) => u.id) || []);
      const newUsuarios = backup.data.usuarios?.filter((u: any) => !existingUsuariosIds.has(u.id)) || [];
      if (newUsuarios.length > 0) await supabase.from('usuarios').insert(newUsuarios);

      const { data: existingMaterias } = await supabase.from('materias').select('id');
      const existingMateriasIds = new Set(existingMaterias?.map((m) => m.id) || []);
      const newMaterias = backup.data.materias?.filter((m: any) => !existingMateriasIds.has(m.id)) || [];
      if (newMaterias.length > 0) await supabase.from('materias').insert(newMaterias);

      // Ahora insertaremos los demás usando upsert para evitar errores de duplicados/llaves
      // Teniendo cuidado con llaves foráneas
      const tablesList = [
        'noticias', 'foto_noticia', 'horarios', 'planes_evaluacion',
        'ausencias', 'documentos_institucionales', 'configuracion_sistema', 'log_sistema'
      ];

      for (const tableName of tablesList) {
        if (backup.data[tableName] && backup.data[tableName].length > 0) {
          await supabase.from(tableName as any).upsert(backup.data[tableName], { onConflict: 'id' }).select();
        }
      }

      setMessage({ type: 'success', text: 'Backup restaurado exitosamente' });
      setShowRestoreModal(false);
      setBackupData('');
    } catch (error) {
      const err = error as Error;
      console.error('Error importing backup:', err);
      setMessage({ type: 'error', text: err.message || 'Error al restaurar el backup' });
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        setBackupData(event.target?.result as string);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div>
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900">Sistema de Respaldo</h1>
        <p className="text-gray-600 mt-2">Exporta e importa los datos del sistema de forma segura</p>
      </div>

      {message && (
        <div
          className={`mb-6 p-4 rounded-lg flex items-center ${message.type === 'success'
            ? 'bg-green-50 text-green-800 border border-green-200'
            : 'bg-red-50 text-red-800 border border-red-200'
            }`}
        >
          {message.type === 'success' ? (
            <CheckCircle className="w-5 h-5 mr-3" />
          ) : (
            <AlertTriangle className="w-5 h-5 mr-3" />
          )}
          <span>{message.text}</span>
        </div>
      )}

      <div className="grid md:grid-cols-2 gap-6">
        <div className="bg-white rounded-xl shadow-md p-8">
          <div className="bg-blue-100 rounded-full w-16 h-16 flex items-center justify-center mb-6 mx-auto">
            <Download className="w-8 h-8 text-blue-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 text-center mb-4">Exportar Datos</h2>
          <p className="text-gray-600 text-center mb-6">
            Descarga un archivo JSON con todos los datos del sistema
          </p>
          <button
            onClick={handleExport}
            disabled={loading}
            className="w-full bg-blue-600 text-white py-3 rounded-lg font-semibold hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center"
          >
            <Download className="w-5 h-5 mr-2" />
            {loading ? 'Exportando...' : 'Exportar Backup'}
          </button>
        </div>

        <div className="bg-white rounded-xl shadow-md p-8">
          <div className="bg-orange-100 rounded-full w-16 h-16 flex items-center justify-center mb-6 mx-auto">
            <Upload className="w-8 h-8 text-orange-600" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 text-center mb-4">Importar Datos</h2>
          <p className="text-gray-600 text-center mb-6">
            Restaura o migra datos desde un archivo de backup
          </p>
          <button
            onClick={() => setShowRestoreModal(true)}
            className="w-full bg-orange-500 text-white py-3 rounded-lg font-semibold hover:bg-orange-600 transition flex items-center justify-center"
          >
            <Upload className="w-5 h-5 mr-2" />
            Importar Backup
          </button>
        </div>
      </div>

      <div className="mt-8 bg-yellow-50 border-l-4 border-yellow-400 p-6 rounded-lg">
        <div className="flex items-start">
          <AlertTriangle className="w-6 h-6 text-yellow-600 mr-3 flex-shrink-0 mt-1" />
          <div>
            <h3 className="text-lg font-bold text-yellow-900 mb-2">Advertencias Importantes</h3>
            <ul className="text-yellow-800 space-y-2 list-disc list-inside">
              <li>La importación reemplazará datos en caso de conflicto de IDs.</li>
              <li>El orden de inserción respeta las relaciones del esquema de 11 tablas.</li>
              <li>Asegúrate de tener conexión al servidor para validar llaves foráneas (ej. Auth).</li>
              <li>Siempre realiza un backup antes de importar nuevos datos.</li>
            </ul>
          </div>
        </div>
      </div>

      {showRestoreModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black bg-opacity-50">
          <div className="bg-white rounded-xl shadow-2xl max-w-2xl w-full p-6">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-2xl font-bold text-gray-900">Importar Backup</h2>
              <button
                onClick={() => {
                  setShowRestoreModal(false);
                  setBackupData('');
                }}
                className="text-gray-400 hover:text-gray-600"
              >
                <AlertTriangle className="w-6 h-6" />
              </button>
            </div>

            <div className="mb-6">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Selecciona el archivo de backup
              </label>
              <input
                type="file"
                accept=".json"
                onChange={handleFileUpload}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
              />
            </div>

            {backupData && (
              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Vista previa del backup
                </label>
                <textarea
                  value={backupData}
                  readOnly
                  rows={10}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg bg-gray-50 font-mono text-sm"
                />
              </div>
            )}

            <div className="flex justify-end gap-3">
              <button
                onClick={() => {
                  setShowRestoreModal(false);
                  setBackupData('');
                }}
                className="px-5 py-2.5 border border-gray-300 rounded-lg text-gray-700 font-medium hover:bg-gray-50 transition"
              >
                Cancelar
              </button>
              <button
                onClick={handleImport}
                disabled={!backupData || loading}
                className="px-5 py-2.5 bg-orange-500 text-white rounded-lg font-medium hover:bg-orange-600 transition disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {loading ? 'Importando...' : 'Restaurar Backup'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/Layout';
import { FormModal } from '../components/FormModal';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { supabase, DocumentosInstitucionales } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';
import { FolderOpen, Plus, Trash2, FileText, Upload } from 'lucide-react';

export const Documents: React.FC = () => {
  const { userRole } = useAuth();
  const [documents, setDocuments] = useState<DocumentosInstitucionales[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [documentToDelete, setDocumentToDelete] = useState<DocumentosInstitucionales | null>(null);
  const [formData, setFormData] = useState({
    titulo: '',
    file: null as File | null,
  });

  const canManage = userRole === 'administrador' || userRole === 'secretaría';

  useEffect(() => {
    fetchDocuments();
  }, []);

  const fetchDocuments = async () => {
    try {
      const { data, error } = await supabase
        .from('documentos_institucionales')
        .select('*')
        .order('created_at', { ascending: false });

      if (error) throw error;
      setDocuments(data || []);
    } catch (error) {
      console.error('Error fetching documents:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.file) return;

    setUploading(true);
    try {
      const fileExt = formData.file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
      const filePath = `documentos_institucionales/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('documentos_pdf')
        .upload(filePath, formData.file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('documentos_pdf')
        .getPublicUrl(filePath);

      const { error: insertError } = await supabase
        .from('documentos_institucionales')
        .insert([
          {
            titulo: formData.titulo,
            ruta_pdf: publicUrl,
          },
        ]);

      if (insertError) throw insertError;

      await fetchDocuments();
      handleCloseModal();
    } catch (error: any) {
      console.error('Error uploading document:', error);
      alert('Error al subir el documento: ' + (error.message || 'Error desconocido'));
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async () => {
    if (!documentToDelete) return;

    try {
      const filePath = documentToDelete.ruta_pdf.split('/documentos_pdf/')[1];
      if (filePath) {
        await supabase.storage
          .from('documentos_pdf')
          .remove([filePath]);
      }

      const { error } = await supabase
        .from('documentos_institucionales')
        .delete()
        .eq('id', documentToDelete.id);

      if (error) throw error;
      await fetchDocuments();
      setDocumentToDelete(null);
    } catch (error) {
      console.error('Error deleting document:', error);
      alert('Error al eliminar el documento');
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setFormData({
      titulo: '',
      file: null,
    });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.type !== 'application/pdf') {
        alert('Solo se permiten archivos PDF');
        return;
      }
      if (file.size > 10 * 1024 * 1024) {
        alert('El archivo no debe superar los 10MB');
        return;
      }
      setFormData({ ...formData, file });
    }
  };

  if (loading) {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-100 p-3 rounded-xl">
              <FolderOpen className="w-8 h-8 text-indigo-600" />
            </div>
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Documentos Institucionales</h1>
              <p className="text-gray-600">Archivos y normativas del plantel</p>
            </div>
          </div>
          {canManage && (
            <button
              onClick={() => setShowModal(true)}
              className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-lg hover:bg-indigo-700 transition"
            >
              <Plus className="w-5 h-5" />
              Subir Documento
            </button>
          )}
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {documents.length === 0 ? (
            <div className="col-span-full bg-white rounded-xl shadow-sm p-12 text-center">
              <FolderOpen className="w-16 h-16 text-gray-400 mx-auto mb-4" />
              <h3 className="text-xl font-semibold text-gray-900 mb-2">No hay documentos</h3>
              <p className="text-gray-600">
                {canManage ? 'Sube el primer documento institucional' : 'No hay documentos disponibles aún'}
              </p>
            </div>
          ) : (
            documents.map((doc) => (
              <div
                key={doc.id}
                className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 hover:shadow-md transition group"
              >
                <div className="flex items-start justify-between mb-4">
                  <div className="bg-red-50 p-3 rounded-lg group-hover:bg-red-100 transition">
                    <FileText className="w-8 h-8 text-red-500" />
                  </div>
                  {canManage && (
                    <button
                      onClick={() => setDocumentToDelete(doc)}
                      className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition opacity-0 group-hover:opacity-100"
                      title="Eliminar documento"
                    >
                      <Trash2 className="w-5 h-5" />
                    </button>
                  )}
                </div>

                <h3 className="text-lg font-bold text-gray-900 mb-2 line-clamp-2" title={doc.titulo}>
                  {doc.titulo}
                </h3>

                <p className="text-sm text-gray-500 mb-6 flex items-center gap-2">
                  <span className="w-1.5 h-1.5 rounded-full bg-gray-300"></span>
                  {new Date(doc.created_at).toLocaleDateString('es-ES')}
                </p>

                <div className="flex gap-3">
                  <a
                    href={doc.ruta_pdf}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="flex-1 text-center bg-indigo-50 text-indigo-700 font-medium py-2 px-4 rounded-lg hover:bg-indigo-100 transition"
                  >
                    Ver Documento
                  </a>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      <FormModal
        isOpen={showModal}
        onClose={handleCloseModal}
        title="Subir Nuevo Documento"
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Título del Documento
            </label>
            <input
              type="text"
              value={formData.titulo}
              onChange={(e) => setFormData({ ...formData, titulo: e.target.value })}
              placeholder="Ej: Reglamento Interno 2024"
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Archivo PDF
            </label>
            <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-indigo-500 transition cursor-pointer bg-gray-50">
              <input
                type="file"
                accept=".pdf"
                onChange={handleFileChange}
                className="hidden"
                id="doc-upload"
                required
              />
              <label
                htmlFor="doc-upload"
                className="cursor-pointer flex flex-col items-center w-full h-full"
              >
                <div className="bg-white p-3 rounded-full shadow-sm mb-3">
                  <Upload className="w-8 h-8 text-indigo-500" />
                </div>
                <span className="text-sm font-medium text-gray-700 mb-1">
                  {formData.file ? formData.file.name : 'Seleccionar archivo PDF'}
                </span>
                <span className="text-xs text-gray-500">
                  {formData.file ? `${(formData.file.size / (1024 * 1024)).toFixed(2)} MB` : 'Máximo 10MB'}
                </span>
              </label>
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={handleCloseModal}
              className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium"
              disabled={uploading}
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition font-medium disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              disabled={uploading || !formData.file}
            >
              {uploading ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                  <span>Subiendo...</span>
                </>
              ) : (
                <>
                  <Upload className="w-4 h-4" />
                  <span>Subir Documento</span>
                </>
              )}
            </button>
          </div>
        </form>
      </FormModal>

      <ConfirmDialog
        isOpen={!!documentToDelete}
        onClose={() => setDocumentToDelete(null)}
        onConfirm={handleDelete}
        title="Eliminar Documento"
        message={`¿Estás seguro de que deseas eliminar el documento "${documentToDelete?.titulo}"? Esta acción no se puede deshacer y el archivo PDF se borrará permanentemente.`}
        confirmText="Sí, eliminar"
        cancelText="Cancelar"
        type="danger"
      />
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/Layout';
import { FileUp, BookOpen, CheckCircle, Trash2, Download, AlertCircle, Loader2 } from 'lucide-react';
import { supabase, PlanesEvaluacion, Materias } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';

export const EvaluationPlans: React.FC = () => {
  const { userRole } = useAuth();
  const [plans, setPlans] = useState<PlanesEvaluacion[]>([]);
  const [materias, setMaterias] = useState<Materias[]>([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  // Form state
  const [anoEscolar, setAnoEscolar] = useState('');
  const [materiaId, setMateriaId] = useState('');
  const [file, setFile] = useState<File | null>(null);

  const canEdit = userRole === 'administrador' || userRole === 'secretaría';

  const fetchInitialData = async () => {
    try {
      const [plansRes, materiasRes] = await Promise.all([
        supabase
          .from('planes_evaluacion')
          .select('*, materias(nombre_materia)')
          .order('created_at', { ascending: false }),
        supabase
          .from('materias')
          .select('*')
          .order('nombre_materia', { ascending: true })
      ]);

      if (plansRes.error) throw plansRes.error;
      if (materiasRes.error) throw materiasRes.error;

      setPlans(plansRes.data || []);
      setMaterias(materiasRes.data || []);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchInitialData();
  }, []);

  const handleSave = async () => {
    if (!anoEscolar || !materiaId || !file) {
      setErrorMessage('Por favor, complete los campos obligatorios y seleccione un archivo PDF.');
      setStatus('error');
      setTimeout(() => setStatus('idle'), 3000);
      return;
    }

    setUploading(true);
    setStatus('idle');
    setErrorMessage('');

    try {
      const fileExt = file.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2, 9)}.${fileExt}`;
      const filePath = `planes_evaluacion/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('documentos_pdf')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('documentos_pdf')
        .getPublicUrl(filePath);

      const { error: dbError } = await supabase
        .from('planes_evaluacion')
        .insert([
          {
            anio_escolar: anoEscolar,
            materia: materiaId,
            ruta_pdf: publicUrl,
          }
        ]);

      if (dbError) throw dbError;

      setStatus('success');
      setAnoEscolar('');
      setMateriaId('');
      setFile(null);

      const fileInput = document.getElementById('file-upload') as HTMLInputElement;
      if (fileInput) fileInput.value = '';

      fetchInitialData();
      setTimeout(() => setStatus('idle'), 3000);
    } catch (error: any) {
      console.error('Upload Error:', error);
      setErrorMessage(error.message || 'Error al subir el plan de evaluación');
      setStatus('error');
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async (id: string, ruta_pdf: string) => {
    if (!confirm('¿Está seguro de eliminar este plan de evaluación?')) return;

    try {
      const filePath = ruta_pdf.split('/documentos_pdf/')[1];
      if (filePath) {
        await supabase.storage.from('documentos_pdf').remove([filePath]);
      }

      const { error } = await supabase
        .from('planes_evaluacion')
        .delete()
        .eq('id', id);

      if (error) throw error;
      fetchInitialData();
    } catch (error) {
      console.error('Delete Error:', error);
      alert('Error al eliminar el plan');
    }
  };

  return (
    <Layout>
      <div className="p-6">
        <h1 className="text-2xl font-bold mb-6 flex items-center gap-2">
          <BookOpen className="text-blue-600" /> Planes de Evaluación
        </h1>

        {canEdit && (
          <div className="bg-white p-6 rounded-xl shadow-md border border-gray-100 mb-8">
            <h2 className="text-lg font-semibold mb-4 text-gray-800">Cargar Nuevo Plan</h2>

            {status === 'error' && (
              <div className="mb-4 p-3 bg-red-50 text-red-600 rounded-lg flex items-center gap-2">
                <AlertCircle size={20} />
                <span>{errorMessage}</span>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Año Escolar *</label>
                <select
                  className="w-full border rounded-lg p-2 bg-gray-50 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={anoEscolar}
                  onChange={(e) => setAnoEscolar(e.target.value)}
                >
                  <option value="">Seleccione año...</option>
                  <option value="1er Año">1er Año</option>
                  <option value="2do Año">2do Año</option>
                  <option value="3er Año">3er Año</option>
                  <option value="4to Año">4to Año</option>
                  <option value="5to Año">5to Año</option>
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Materia *</label>
                {materias.length === 0 ? (
                  <p className="text-sm text-red-500 mt-2">No hay materias registradas. Pide a un administrador que cree materias desde la base de datos.</p>
                ) : (
                  <select
                    className="w-full border rounded-lg p-2 bg-gray-50 focus:ring-2 focus:ring-blue-500 outline-none"
                    value={materiaId}
                    onChange={(e) => setMateriaId(e.target.value)}
                  >
                    <option value="">Seleccione materia...</option>
                    {materias.map(m => (
                      <option key={m.id} value={m.id}>{m.nombre_materia}</option>
                    ))}
                  </select>
                )}
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Cargar PDF *</label>
                <input
                  id="file-upload"
                  type="file"
                  accept=".pdf"
                  onChange={(e) => setFile(e.target.files?.[0] || null)}
                  className="block w-full text-sm text-gray-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
                />
              </div>
            </div>

            <button
              onClick={handleSave}
              disabled={uploading || materias.length === 0}
              className={`w-full md:w-auto px-6 py-3 rounded-lg font-bold flex items-center justify-center gap-2 transition-all ${status === 'success' ? 'bg-green-600 text-white' :
                uploading || materias.length === 0 ? 'bg-blue-400 text-white cursor-not-allowed' :
                  'bg-blue-600 text-white hover:bg-blue-700'
                }`}
            >
              {status === 'success' ? (
                <><CheckCircle size={20} /> ¡Plan Guardado!</>
              ) : uploading ? (
                <><Loader2 size={20} className="animate-spin" /> Subiendo...</>
              ) : (
                <><FileUp size={20} /> Publicar Plan de Evaluación</>
              )}
            </button>
          </div>
        )}

        <div className="bg-white rounded-xl shadow-md border border-gray-100 overflow-hidden">
          <div className="p-4 bg-gray-50 border-b font-semibold text-gray-700">
            Planes de Evaluación Publicados
          </div>

          {loading ? (
            <div className="p-8 text-center text-gray-500 flex flex-col items-center">
              <Loader2 className="w-8 h-8 animate-spin text-blue-500 mb-2" />
              Cargando planes...
            </div>
          ) : plans.length === 0 ? (
            <div className="p-8 text-center text-gray-500">
              No hay planes de evaluación publicados aún.
            </div>
          ) : (
            <div className="divide-y">
              {plans.map((plan) => (
                <div key={plan.id} className="p-4 flex flex-col md:flex-row md:items-center justify-between gap-4 hover:bg-gray-50 transition">
                  <div>
                    <div className="flex items-center gap-2">
                      <span className="font-bold text-lg text-gray-800">{plan.materias?.nombre_materia || 'Materia Eliminada'}</span>
                      <span className="px-2 py-1 bg-blue-100 text-blue-800 text-xs rounded-full font-medium">
                        {plan.anio_escolar}
                      </span>
                    </div>
                    <div className="text-xs text-gray-400 mt-2">
                      Publicado el: {new Date(plan.created_at).toLocaleDateString('es-ES')}
                    </div>
                  </div>

                  <div className="flex items-center gap-2 self-end md:self-auto">
                    <a
                      href={plan.ruta_pdf}
                      target="_blank"
                      rel="noopener noreferrer"
                      className="px-4 py-2 bg-blue-50 text-blue-600 hover:bg-blue-100 rounded-lg flex items-center gap-2 text-sm font-medium transition"
                    >
                      <Download size={16} /> Ver/Descargar PDF
                    </a>

                    {canEdit && (
                      <button
                        onClick={() => handleDelete(plan.id, plan.ruta_pdf)}
                        className="p-2 text-red-500 hover:bg-red-50 rounded-lg transition"
                        title="Eliminar Plan"
                      >
                        <Trash2 size={18} />
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/Layout';
import { FormModal } from '../components/FormModal';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { supabase, Noticias, FotoNoticia } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';
import { Newspaper, Plus, Trash2, Image as ImageIcon, Upload } from 'lucide-react';

interface NoticiaConFotos extends Noticias {
  fotos: FotoNoticia[];
}

export const News: React.FC = () => {
  const { userRole } = useAuth();
  const [news, setNews] = useState<NoticiaConFotos[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [newsToDelete, setNewsToDelete] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    titulo: '',
    contenido: '',
    file: null as File | null,
  });

  const canManage = userRole === 'administrador' || userRole === 'secretaría';

  useEffect(() => {
    fetchNews();
  }, []);

  const fetchNews = async () => {
    try {
      const { data: noticiasData, error: noticiasError } = await supabase
        .from('noticias')
        .select('*')
        .order('fecha', { ascending: false });

      if (noticiasError) throw noticiasError;

      if (noticiasData) {
        const { data: fotosData, error: fotosError } = await supabase
          .from('foto_noticia')
          .select('*');

        if (fotosError) throw fotosError;

        const combinedNews: NoticiaConFotos[] = noticiasData.map((noticia: Noticias) => ({
          ...noticia,
          fotos: (fotosData || []).filter((foto: FotoNoticia) => foto.id_noticia === noticia.id)
        }));

        setNews(combinedNews);
      }
    } catch (error) {
      console.error('Error fetching news:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    setUploading(true);
    try {
      // 1. Crear la Noticia
      const { data: noticiaCreada, error: insertError } = await supabase
        .from('noticias')
        .insert([
          {
            titulo: formData.titulo,
            contenido: formData.contenido,
            fecha: new Date().toISOString(),
          },
        ])
        .select()
        .single();

      if (insertError) throw insertError;

      // 2. Subir imagen si existe
      if (formData.file && noticiaCreada) {
        const fileExt = formData.file.name.split('.').pop();
        const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
        const filePath = `noticias/${fileName}`;

        const { error: uploadError } = await supabase.storage
          .from('imagenes_sistema')
          .upload(filePath, formData.file);

        if (uploadError) throw uploadError;

        const { data: { publicUrl } } = supabase.storage
          .from('imagenes_sistema')
          .getPublicUrl(filePath);

        const { error: fotoError } = await supabase
          .from('foto_noticia')
          .insert([
            {
              id_noticia: noticiaCreada.id,
              ruta_foto: publicUrl,
            },
          ]);

        if (fotoError) throw fotoError;
      }

      await fetchNews();
      handleCloseModal();
    } catch (error: any) {
      console.error('Error al crear noticia:', error);
      alert('Error: ' + (error.message || 'Error desconocido'));
    } finally {
      setUploading(false);
    }
  };

  const handleDelete = async () => {
    if (!newsToDelete) return;

    try {
      // Find photos
      const noticia = news.find(n => n.id === newsToDelete);
      if (noticia && noticia.fotos.length > 0) {
        for (const foto of noticia.fotos) {
          const filePath = foto.ruta_foto.split('/imagenes_sistema/')[1];
          if (filePath) {
            await supabase.storage
              .from('imagenes_sistema')
              .remove([filePath]);
          }
        }
      }

      const { error } = await supabase
        .from('noticias')
        .delete()
        .eq('id', newsToDelete);

      if (error) throw error;

      await fetchNews();
      setNewsToDelete(null);
    } catch (error) {
      console.error('Error deleting news:', error);
      alert('Error al eliminar la noticia');
    }
  };

  const handleCloseModal = () => {
    setShowModal(false);
    setFormData({
      titulo: '',
      contenido: '',
      file: null,
    });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (!file.type.startsWith('image/')) {
        alert('Solo se permiten imágenes (JPG, PNG, WebP)');
        return;
      }
      if (file.size > 5 * 1024 * 1024) {
        alert('La imagen no debe superar los 5MB');
        return;
      }
      setFormData({ ...formData, file });
    }
  };

  if (loading) {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-6xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div className="flex items-center gap-3">
            <div className="bg-orange-100 p-3 rounded-xl">
              <Newspaper className="w-8 h-8 text-orange-600" />
            </div>
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Noticias y Avisos</h1>
              <p className="text-gray-600">Información relevante para la comunidad escolar</p>
            </div>
          </div>
          {canManage && (
            <button
              onClick={() => setShowModal(true)}
              className="flex items-center gap-2 bg-orange-600 text-white px-4 py-2 rounded-lg hover:bg-orange-700 transition"
            >
              <Plus className="w-5 h-5" />
              Crear Noticia
            </button>
          )}
        </div>

        <div className="flex flex-col gap-6">
          {news.length === 0 ? (
            <div className="bg-white rounded-xl shadow-sm p-12 text-center">
              <Newspaper className="w-16 h-16 text-gray-400 mx-auto mb-4" />
              <h3 className="text-xl font-semibold text-gray-900 mb-2">No hay noticias</h3>
              <p className="text-gray-600">
                {canManage ? 'Publica el primer aviso o noticia escolar' : 'No hay noticias disponibles en este momento'}
              </p>
            </div>
          ) : (
            news.map((item) => (
              <div
                key={item.id}
                className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-md transition flex flex-col md:flex-row"
              >
                {item.fotos.length > 0 ? (
                  <div className="md:w-1/3 h-48 md:h-auto overflow-hidden relative">
                    <img
                      src={item.fotos[0].ruta_foto}
                      alt={item.titulo}
                      className="w-full h-full object-cover transition duration-300 hover:scale-105"
                    />
                  </div>
                ) : (
                  <div className="hidden md:flex md:w-1/4 bg-orange-50 items-center justify-center p-6 text-center text-orange-300">
                    <Newspaper size={64} />
                  </div>
                )}
                <div className="p-6 flex-1 flex flex-col justify-between">
                  <div>
                    <div className="flex items-start justify-between mb-2">
                      <h3 className="text-2xl font-bold text-gray-900">{item.titulo}</h3>
                      {canManage && (
                        <button
                          onClick={() => setNewsToDelete(item.id)}
                          className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition"
                          title="Eliminar noticia"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      )}
                    </div>
                    <p className="text-sm text-gray-500 mb-4 font-medium flex items-center gap-2">
                      <span className="w-2 h-2 rounded-full bg-orange-500"></span>
                      Publicado el {new Date(item.fecha).toLocaleDateString('es-ES')}
                    </p>
                    <div className="text-gray-700 whitespace-pre-line mb-4">
                      {item.contenido}
                    </div>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      <FormModal
        isOpen={showModal}
        onClose={handleCloseModal}
        title="Crear Nueva Noticia o Aviso"
      >
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Título
            </label>
            <input
              type="text"
              value={formData.titulo}
              onChange={(e) => setFormData({ ...formData, titulo: e.target.value })}
              placeholder="Ej: Suspensión de actividades por lluvia"
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Contenido de la Noticia
            </label>
            <textarea
              value={formData.contenido}
              onChange={(e) => setFormData({ ...formData, contenido: e.target.value })}
              placeholder="Escribe el cuerpo completo de la noticia..."
              className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-orange-500 focus:border-transparent min-h-[150px]"
              required
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Imagen (Opcional)
            </label>
            <div className="border-2 border-dashed border-gray-300 rounded-lg p-6 text-center hover:border-orange-500 transition cursor-pointer bg-gray-50">
              <input
                type="file"
                accept="image/*"
                onChange={handleFileChange}
                className="hidden"
                id="img-upload"
              />
              <label
                htmlFor="img-upload"
                className="cursor-pointer flex flex-col items-center w-full h-full"
              >
                <div className="bg-white p-3 rounded-full shadow-sm mb-3">
                  <ImageIcon className="w-8 h-8 text-orange-500" />
                </div>
                <span className="text-sm font-medium text-gray-700 mb-1">
                  {formData.file ? formData.file.name : 'Añadir foto a la noticia'}
                </span>
                <span className="text-xs text-gray-500">
                  {formData.file ? `${(formData.file.size / (1024 * 1024)).toFixed(2)} MB` : 'PNG, JPG. Máximo 5MB'}
                </span>
              </label>
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={handleCloseModal}
              className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-lg hover:bg-gray-50 transition font-medium"
              disabled={uploading}
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 bg-orange-600 text-white rounded-lg hover:bg-orange-700 transition font-medium disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              disabled={uploading || !formData.titulo || !formData.contenido}
            >
              {uploading ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                  <span>Publicando...</span>
                </>
              ) : (
                <>
                  <Upload className="w-4 h-4" />
                  <span>Publicar Noticia</span>
                </>
              )}
            </button>
          </div>
        </form>
      </FormModal>

      <ConfirmDialog
        isOpen={!!newsToDelete}
        onClose={() => setNewsToDelete(null)}
        onConfirm={handleDelete}
        title="Eliminar Noticia"
        message={`¿Estás seguro de que deseas eliminar esta noticia? Las fotos asociadas también se borrarán permanentemente.`}
        confirmText="Sí, eliminar"
        cancelText="Cancelar"
        type="danger"
      />
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/Layout';
import { supabase } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';
import {
  BarChart,
  Bar,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  PieChart,
  Pie,
  Cell
} from 'recharts';
import { TrendingUp, Users as UsersIcon, FileText, Calendar, BookOpen } from 'lucide-react';

export const Statistics: React.FC = () => {
  const { userRole } = useAuth();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({
    usuariosPorRol: [] as any[],
    ausenciasPorEstado: [] as any[],
    actividadReciente: [] as any[],
    resumenMensual: [] as any[]
  });

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  useEffect(() => {
    fetchStatistics();
  }, [userRole]);

  const fetchStatistics = async () => {
    if (userRole !== 'administrador') return;

    try {
      // 1. Usuarios por rol
      const { data: usersData } = await supabase.from('usuarios').select('id, id_rol, roles(nombre_rol)');
      const rolesCount: Record<string, number> = {};

      usersData?.forEach(user => {
        const roleName = user.roles?.nombre_rol || 'Desconocido';
        rolesCount[roleName] = (rolesCount[roleName] || 0) + 1;
      });

      const usuariosPorRol = Object.entries(rolesCount).map(([name, value]) => ({ name, value }));

      // 2. Ausencias por estado
      const { data: absencesData } = await supabase.from('ausencias').select('estado');
      const estadosCount: Record<string, number> = {};

      absencesData?.forEach(abs => {
        const estado = abs.estado || 'pendiente';
        estadosCount[estado] = (estadosCount[estado] || 0) + 1;
      });

      const ausenciasPorEstado = Object.entries(estadosCount).map(([name, value]) => ({ name, value }));

      // 3. Actividad Reciente (Últimos 6 meses)
      const sixMonthsAgo = new Date();
      sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6);

      const fetchMonthlyData = async (table: string, dateCol = 'created_at') => {
        const { data } = await supabase
          .from(table)
          .select(dateCol)
          .gte(dateCol, sixMonthsAgo.toISOString());

        const monthlyCount: Record<string, number> = {};
        data?.forEach(item => {
          const date = new Date(item[dateCol]);
          const monthKey = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
          monthlyCount[monthKey] = (monthlyCount[monthKey] || 0) + 1;
        });
        return monthlyCount;
      };

      const [mensualAusencias, mensualHorarios, mensualPlanes] = await Promise.all([
        fetchMonthlyData('ausencias'),
        fetchMonthlyData('horarios'),
        fetchMonthlyData('planes_evaluacion')
      ]);

      const meses = Array.from({ length: 6 }, (_, i) => {
        const d = new Date();
        d.setMonth(d.getMonth() - i);
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`;
      }).reverse();

      const resumenMensual = meses.map(month => ({
        mes: month,
        Ausencias: mensualAusencias[month] || 0,
        Horarios: mensualHorarios[month] || 0,
        Planes: mensualPlanes[month] || 0
      }));

      // 4. Totales Globales
      const { count: uCount } = await supabase.from('usuarios').select('*', { count: 'exact', head: true });
      const { count: aCount } = await supabase.from('ausencias').select('*', { count: 'exact', head: true });
      const { count: pCount } = await supabase.from('planes_evaluacion').select('*', { count: 'exact', head: true });
      const { count: hCount } = await supabase.from('horarios').select('*', { count: 'exact', head: true });

      setStats({
        usuariosPorRol,
        ausenciasPorEstado,
        resumenMensual,
        actividadReciente: [
          { nombre: 'Usuarios', total: uCount || 0, icon: UsersIcon, color: 'text-blue-600', bg: 'bg-blue-100' },
          { nombre: 'Inasistencias', total: aCount || 0, icon: FileText, color: 'text-orange-600', bg: 'bg-orange-100' },
          { nombre: 'Horarios', total: hCount || 0, icon: Calendar, color: 'text-purple-600', bg: 'bg-purple-100' },
          { nombre: 'Planes Eval.', total: pCount || 0, icon: BookOpen, color: 'text-green-600', bg: 'bg-green-100' },
        ]
      });

    } catch (error) {
      console.error('Error fetching statistics:', error);
    } finally {
      setLoading(false);
    }
  };

  if (userRole !== 'administrador') {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <p className="text-gray-500 text-lg">No tienes permisos para ver las estadísticas.</p>
        </div>
      </Layout>
    );
  }

  if (loading) {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
          <TrendingUp className="text-blue-600" /> Estadísticas Generales
        </h1>
        <p className="text-gray-600 mt-2">Métricas e indicadores del sistema académico</p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {stats.actividadReciente.map((item, index) => {
          const Icon = item.icon;
          return (
            <div key={index} className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center gap-4">
              <div className={`${item.bg} p-4 rounded-lg`}>
                <Icon className={`w-8 h-8 ${item.color}`} />
              </div>
              <div>
                <p className="text-sm text-gray-500 font-medium">{item.nombre}</p>
                <p className="text-2xl font-bold text-gray-900">{item.total}</p>
              </div>
            </div>
          );
        })}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="text-lg font-bold text-gray-900 mb-6">Actividad Mensual</h2>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.resumenMensual}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis dataKey="mes" />
                <YAxis />
                <Tooltip />
                <Legend />
                <Bar dataKey="Ausencias" fill="#f59e0b" />
                <Bar dataKey="Horarios" fill="#8b5cf6" />
                <Bar dataKey="Planes" fill="#10b981" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <h2 className="text-lg font-bold text-gray-900 mb-6">Distribución de Usuarios por Rol</h2>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.usuariosPorRol}
                  cx="50%"
                  cy="50%"
                  labelLine={false}
                  label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                  outerRadius={100}
                  fill="#8884d8"
                  dataKey="value"
                >
                  {stats.usuariosPorRol.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 lg:col-span-2">
          <h2 className="text-lg font-bold text-gray-900 mb-6">Estado de Inasistencias</h2>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats.ausenciasPorEstado} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis type="number" />
                <YAxis dataKey="name" type="category" />
                <Tooltip />
                <Legend />
                <Bar dataKey="value" fill="#ef4444" name="Cantidad" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from '../components/Layout';
import { FormModal } from '../components/FormModal';
import { ConfirmDialog } from '../components/ConfirmDialog';
import { supabase, Usuarios, Roles } from '../lib/supabase';
import { useAuth } from '../contexts/AuthContext';
import { Users as UsersIcon, Search, UserPlus, Shield, User, Mail, Trash2, Edit2, Key } from 'lucide-react';

export const Users: React.FC = () => {
  const { userRole } = useAuth();
  const [users, setUsers] = useState<Usuarios[]>([]);
  const [roles, setRoles] = useState<Roles[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [showModal, setShowModal] = useState(false);
  const [userToDelete, setUserToDelete] = useState<Usuarios | null>(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [usersResponse, rolesResponse] = await Promise.all([
        supabase
          .from('usuarios')
          .select('*, roles(nombre_rol)')
          .order('created_at', { ascending: false }),
        supabase.from('roles').select('*')
      ]);

      if (usersResponse.error) throw usersResponse.error;
      if (rolesResponse.error) throw rolesResponse.error;

      setUsers(usersResponse.data || []);
      setRoles(rolesResponse.data || []);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async () => {
    if (!userToDelete) return;

    try {
      // In Supabase, deleting from `usuarios` depends on relationships.
      // Usually, deleting the auth user requires Admin API access or an RPC.
      // The user mentioned an RPC `delete_user` in the past. 
      // Assuming it's still available or we just delete from the public schema.
      const { error } = await supabase.rpc('delete_user', { user_id: userToDelete.id });

      if (error) {
        // Fallback just deleting from public if RPC fails
        const { error: fallbackError } = await supabase.from('usuarios').delete().eq('id', userToDelete.id);
        if (fallbackError) throw fallbackError;
      }

      await fetchData();
      setUserToDelete(null);
    } catch (error) {
      console.error('Error deleting user:', error);
      alert('Error al eliminar el usuario. Es posible que tenga registros asociados.');
    }
  };

  const filteredUsers = users.filter(user =>
    user.nombre_completo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.correo.toLowerCase().includes(searchTerm.toLowerCase()) ||
    user.roles?.nombre_rol?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const getRoleBadge = (roleName: string) => {
    switch (roleName.toLowerCase()) {
      case 'administrador':
        return <span className="px-3 py-1 bg-purple-100 text-purple-700 rounded-full text-sm font-medium flex items-center gap-1 w-fit"><Shield className="w-4 h-4" /> Administrador</span>;
      case 'secretaría':
        return <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm font-medium flex items-center gap-1 w-fit"><Key className="w-4 h-4" /> Secretaría</span>;
      default:
        return <span className="px-3 py-1 bg-gray-100 text-gray-700 rounded-full text-sm font-medium flex items-center gap-1 w-fit"><User className="w-4 h-4" /> Representante</span>;
    }
  };

  if (userRole !== 'administrador') {
    return (
      <Layout>
        <div className="flex items-center justify-center h-64">
          <p className="text-gray-500 text-lg">No tienes permisos para gestionar usuarios.</p>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
          <UsersIcon className="text-blue-600" /> Gestión de Usuarios
        </h1>
        <p className="text-gray-600 mt-2">Administra los accesos y roles del sistema</p>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6">
        <div className="flex flex-col md:flex-row gap-4 justify-between mb-6">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-5 h-5" />
            <input
              type="text"
              placeholder="Buscar por nombre, correo o rol..."
              className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <button
            className="flex items-center justify-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition"
            onClick={() => alert('Para añadir usuarios usa el flujo de registro o invita desde Supabase.')}
          >
            <UserPlus className="w-5 h-5" />
            Nuevo Usuario
          </button>
        </div>

        {loading ? (
          <div className="flex justify-center py-12">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="bg-gray-50 text-gray-600 border-b border-gray-200">
                  <th className="px-6 py-4 font-semibold">Usuario</th>
                  <th className="px-6 py-4 font-semibold">Datos de Contacto</th>
                  <th className="px-6 py-4 font-semibold">Rol</th>
                  <th className="px-6 py-4 font-semibold">Fecha Registro</th>
                  <th className="px-6 py-4 font-semibold text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-100">
                {filteredUsers.map((user) => (
                  <tr key={user.id} className="hover:bg-gray-50 transition">
                    <td className="px-6 py-4">
                      <div className="font-semibold text-gray-900">{user.nombre_completo}</div>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-2 text-gray-600 text-sm">
                        <Mail className="w-4 h-4" /> {user.correo}
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      {getRoleBadge(user.roles?.nombre_rol || 'Desconocido')}
                    </td>
                    <td className="px-6 py-4 text-sm text-gray-500">
                      {new Date(user.created_at).toLocaleDateString('es-ES')}
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex items-center justify-end gap-2">
                        <button className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg transition" title="Editar">
                          <Edit2 className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => setUserToDelete(user)}
                          className="p-2 text-red-600 hover:bg-red-50 rounded-lg transition"
                          title="Eliminar"
                        >
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
                {filteredUsers.length === 0 && (
                  <tr>
                    <td colSpan={5} className="px-6 py-8 text-center text-gray-500">
                      No se encontraron usuarios que coincidan con la búsqueda.
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      <ConfirmDialog
        isOpen={!!userToDelete}
        onClose={() => setUserToDelete(null)}
        onConfirm={handleDelete}
        title="Eliminar Usuario"
        message={`¿Estás seguro de que deseas eliminar permanentemente a "${userToDelete?.nombre_completo}"? Esta acción no se puede deshacer.`}
        confirmText="Sí, eliminar"
        cancelText="Cancelar"
        type="danger"
      />
    </Layout>
  );
};
